from fractions import Fraction
from typing import Any
import numpy as np

def rationalize(x: float, max_denom: int = 12) -> str:
    """Convert float to rational string with max denominator."""
    f = Fraction(x).limit_denominator(max_denom)
    return str(f)

def analyze_wyckoff_position_multiplicities_and_coordinates(filepath: str) -> dict[str, Any]:
    """Analyze Wyckoff positions from a CIF file."""
    from pymatgen.core import Structure
    from pymatgen.symmetry.analyzer import SpacegroupAnalyzer

    # Load structure from CIF
    structure = Structure.from_file(filepath)

    # Get spacegroup analyzer
    sym_analyzer = SpacegroupAnalyzer(structure)

    # Get symmetry data
    symmetry_data = sym_analyzer.get_symmetry_dataset()
    if symmetry_data is None:
        raise ValueError("Could not get symmetry information")

    # Get space group info
    spg_info = sym_analyzer.get_space_group_info()

    # Get wyckoff masks from symmetry dataset
    wyckoff_masks = symmetry_data.wyckoff_masks

    # Get equivalent sites
    equivalent_sites = symmetry_data.equivalent_sites

    # Map atoms to their wyckoff positions
    wyckoff_dict = {}
    for idx, site in enumerate(structure):
        wyckoff_label = wyckoff_masks[idx]
        if wyckoff_label not in wyckoff_dict:
            wyckoff_dict[wyckoff_label] = {
                'multiplicity': wyckoff_masks[idx].count('x') + wyckoff_masks[idx].count('y') + wyckoff_masks[idx].count('z') + 1,
                'fract_coords': site.frac_coords
            }

    # Count multiplicities for each Wyckoff letter
    wyckoff_multiplicity_dict = {}
    wyckoff_coordinates_dict = {}

    # Count atoms per wyckoff position
    wyckoff_counts = {}
    for idx, label in enumerate(wyckoff_masks):
        if label not in wyckoff_counts:
            wyckoff_counts[label] = 0
        wyckoff_counts[label] += 1

    # Get first atom coordinates for each wyckoff position
    wyckoff_first_coords = {}
    for idx, site in enumerate(structure):
        label = wyckoff_masks[idx]
        if label not in wyckoff_first_coords:
            wyckoff_first_coords[label] = site.frac_coords

    for label in sorted(wyckoff_counts.keys()):
        wyckoff_multiplicity_dict[label] = wyckoff_counts[label]
        coords = wyckoff_first_coords[label]
        wyckoff_coordinates_dict[label] = [rationalize(c) for c in coords]

    return {
        'wyckoff_multiplicity_dict': wyckoff_multiplicity_dict,
        'wyckoff_coordinates_dict': wyckoff_coordinates_dict
    }

if __name__ == "__main__":
    result = analyze_wyckoff_position_multiplicities_and_coordinates("/root/cif_files/FeS2_mp-226.cif")
    print(result)
